  ('incline-bench-press', '{"id":"incline-bench-press","name":"Incline Barbell Bench Press","category":"compound","equipment":["barbell","bench"],"primary":["chest"],"secondary":["shoulders","triceps"],"difficulty":2,"instructions":["Set bench to 30–45°.","Lower the bar to upper chest.","Press up over the shoulders."]}'::jsonb, 49, true),
  ('pike-pushup', '{"id":"pike-pushup","name":"Pike Push-Up","category":"compound","equipment":["bodyweight"],"primary":["shoulders"],"secondary":["triceps","chest"],"difficulty":2,"instructions":["Hips high in an inverted-V.","Lower the crown of your head toward the floor.","Press back up; the more vertical the torso, the harder."]}'::jsonb, 50, true),
