  ('bulgarian-split-squat', '{"id":"bulgarian-split-squat","name":"Bulgarian Split Squat","category":"compound","equipment":["dumbbell","bodyweight"],"primary":["quads","glutes"],"secondary":["hamstrings"],"difficulty":2,"instructions":["Rear foot elevated on a bench.","Lower the back knee toward the floor.","Drive through the front heel to stand."],"unilateral":true}'::jsonb, 54, true),
  ('rehab-chin-tuck', '{"id":"rehab-chin-tuck","name":"Chin Tuck","category":"rehab","equipment":["bodyweight"],"primary":["traps"],"secondary":[],"difficulty":1,"instructions":["Sit or stand tall, eyes level.","Glide your chin straight back, making a “double chin” — don’t tip the head down.","Hold ~5 seconds, relax, repeat."],"dosage":"2–3 × 10 · 5s holds","rationale":"Re-trains the deep neck flexors and a neutral head position to offload aching upper traps."}'::jsonb, 55, true),
  ('rehab-neck-isometrics', '{"id":"rehab-neck-isometrics","name":"Neck Isometrics","category":"rehab","equipment":["bodyweight"],"primary":["traps"],"secondary":[],"difficulty":1,"instructions":["Place a hand on your forehead; press your head lightly into it without moving — hold ~10s.","Repeat on the back of the head, then each side.","Stay well below any pain; breathe normally."],"dosage":"4 directions × 2 × 10s","rationale":"Gentle pain-free isometrics build neck endurance and calm irritated tissue without moving through range."}'::jsonb, 56, true),
  ('rehab-upper-trap-stretch', '{"id":"rehab-upper-trap-stretch","name":"Upper Trap Stretch","category":"rehab","equipment":["bodyweight"],"primary":["traps"],"secondary":[],"difficulty":1,"instructions":["Sit tall, one hand anchored under your thigh.","Gently tip the opposite ear toward your shoulder until you feel a light stretch.","Hold, breathe, then switch sides."],"dosage":"2–3 × 30s / side","rationale":"Eases tension through the upper trap and levator scapulae that often tags along with neck pain."}'::jsonb, 57, true),
  ('rehab-band-external-rotation', '{"id":"rehab-band-external-rotation","name":"Band External Rotation","category":"rehab","equipment":["bands"],"primary":["shoulders"],"secondary":[],"difficulty":1,"instructions":["Anchor a band at elbow height; hold it across your body, elbow pinned to your side at 90°.","Keeping the elbow glued in, rotate your forearm outward.","Return slowly under control."],"dosage":"2–3 × 12–15 / side","rationale":"Strengthens the rotator cuff (infraspinatus/teres minor) — the workhorse for most shoulder complaints."}'::jsonb, 58, true),
  ('rehab-scap-wall-slide', '{"id":"rehab-scap-wall-slide","name":"Scapular Wall Slide","category":"rehab","equipment":["bodyweight"],"primary":["shoulders"],"secondary":["traps"],"difficulty":1,"instructions":["Stand with back, arms and hands against a wall in a “goalpost”.","Slide your arms up overhead, keeping wrists and elbows on the wall.","Lower slowly, squeezing the shoulder blades down."],"dosage":"2–3 × 10","rationale":"Grooves smooth shoulder-blade upward rotation so overhead motion stops pinching."}'::jsonb, 59, true),
  ('rehab-band-pull-apart', '{"id":"rehab-band-pull-apart","name":"Band Pull-Apart","category":"rehab","equipment":["bands"],"primary":["back"],"secondary":["shoulders","traps"],"difficulty":1,"instructions":["Hold a band at shoulder height, arms straight in front.","Pull the band apart to your chest, squeezing the shoulder blades.","Return slowly; keep ribs down, no shrugging."],"dosage":"2–3 × 15–20","rationale":"Builds mid-back and rear-shoulder strength to balance pressing and support good posture."}'::jsonb, 60, true),
  ('rehab-wall-angel', '{"id":"rehab-wall-angel","name":"Wall Angel","category":"rehab","equipment":["bodyweight"],"primary":["shoulders"],"secondary":["back"],"difficulty":1,"instructions":["Stand with lower back, upper back and head against a wall.","Raise arms into a “W”, then slide to a “Y”, keeping contact with the wall.","Only go as high as you can without pain or arching."],"dosage":"2 × 8–10","rationale":"Restores pain-free overhead range and thoracic extension before you reload pressing."}'::jsonb, 61, true),
  ('rehab-eccentric-wrist-extension', '{"id":"rehab-eccentric-wrist-extension","name":"Eccentric Wrist Extension","category":"rehab","equipment":["dumbbell"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Forearm supported, palm down, holding a light weight.","Use the other hand to help lift the wrist up.","Let go and lower the weight slowly (3–4s) on your own. Repeat."],"dosage":"3 × 15 · slow lower","rationale":"The staple for tennis elbow (lateral): slow eccentrics remodel the extensor tendon."}'::jsonb, 62, true),
  ('rehab-eccentric-wrist-flexion', '{"id":"rehab-eccentric-wrist-flexion","name":"Eccentric Wrist Flexion","category":"rehab","equipment":["dumbbell"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Forearm supported, palm up, holding a light weight.","Assist the wrist up with your other hand.","Lower the weight slowly (3–4s) under control. Repeat."],"dosage":"3 × 15 · slow lower","rationale":"The flexor-side counterpart for golfer’s elbow (medial) tendon pain."}'::jsonb, 63, true),
  ('rehab-supination-curl', '{"id":"rehab-supination-curl","name":"Supination Curl","category":"rehab","equipment":["dumbbell"],"primary":["forearms"],"secondary":["biceps"],"difficulty":1,"instructions":["Hold a light dumbbell by one end, forearm resting on your thigh, palm neutral.","Slowly rotate the palm up, then back down.","Keep it pain-free and controlled."],"dosage":"2–3 × 12 / side","rationale":"Loads forearm rotation gently to rebuild capacity around an irritable elbow."}'::jsonb, 64, true),
  ('rehab-forearm-stretch', '{"id":"rehab-forearm-stretch","name":"Forearm Flexor/Extensor Stretch","category":"rehab","equipment":["bodyweight"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Arm straight in front, palm down; gently pull the hand down and toward you (extensors).","Then palm up; gently pull the fingers back (flexors).","Hold each with a light, pain-free stretch."],"dosage":"2 × 30s each way","rationale":"Decompresses the muscles that pull on an irritated elbow or wrist."}'::jsonb, 65, true),
  ('rehab-wrist-flexion-extension', '{"id":"rehab-wrist-flexion-extension","name":"Wrist Flexion / Extension","category":"rehab","equipment":["bodyweight"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Forearm supported, hand off the edge.","Slowly raise the hand up, then lower it down through a comfortable range.","Add a very light weight only once range is pain-free."],"dosage":"2–3 × 15 each way","rationale":"Restores pain-free wrist range and graded load after a sprain or strain."}'::jsonb, 66, true),
  ('rehab-grip-squeeze', '{"id":"rehab-grip-squeeze","name":"Soft Grip Squeeze","category":"rehab","equipment":["bodyweight"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Squeeze a rolled towel or soft ball.","Hold ~5 seconds, keeping the wrist neutral.","Relax fully between reps; stay pain-free."],"dosage":"3 × 10 · 5s holds","rationale":"Rebuilds grip tolerance without the shear of a loaded bar."}'::jsonb, 67, true),
  ('rehab-wrist-radial-ulnar', '{"id":"rehab-wrist-radial-ulnar","name":"Radial / Ulnar Deviation","category":"rehab","equipment":["bodyweight"],"primary":["forearms"],"secondary":[],"difficulty":1,"instructions":["Forearm resting, thumb up, holding a light object (or nothing).","Tilt the hand up toward the thumb, then down toward the little finger.","Move slowly through a pain-free range."],"dosage":"2 × 12 each way","rationale":"Restores side-to-side wrist control that pressing and gripping depend on."}'::jsonb, 68, true),
  ('rehab-cat-cow', '{"id":"rehab-cat-cow","name":"Cat–Cow","category":"rehab","equipment":["bodyweight"],"primary":["lowerback"],"secondary":["abs"],"difficulty":1,"instructions":["On hands and knees, slowly round the spine up (cat).","Then drop the belly and lift the chest and tailbone (cow).","Move with your breath through a comfortable range."],"dosage":"2 × 10 slow cycles","rationale":"Gentle, pain-free spinal motion that eases stiffness through the whole back."}'::jsonb, 69, true),
  ('rehab-prone-ytw', '{"id":"rehab-prone-ytw","name":"Prone Y-T-W Raises","category":"rehab","equipment":["bodyweight"],"primary":["back"],"secondary":["shoulders","traps"],"difficulty":2,"instructions":["Lie face down, arms forming a “Y” overhead.","Lift the arms a few inches, thumbs up; lower. Repeat as a “T”, then a “W”.","Keep the neck long; lead with the shoulder blades."],"dosage":"2 × 8 each letter","rationale":"Strengthens the mid- and lower-trap that hold the shoulder blades back and down."}'::jsonb, 70, true),
  ('rehab-thoracic-rotation', '{"id":"rehab-thoracic-rotation","name":"Open-Book Thoracic Rotation","category":"rehab","equipment":["bodyweight"],"primary":["back"],"secondary":[],"difficulty":1,"instructions":["Lie on your side, knees bent, arms stacked in front.","Open the top arm across your body, following it with your eyes; let the chest rotate.","Return slowly; keep the knees together."],"dosage":"2 × 8 / side","rationale":"Frees up mid-back rotation so the shoulders and low back don’t compensate."}'::jsonb, 71, true),
  ('rehab-mcgill-curlup', '{"id":"rehab-mcgill-curlup","name":"McGill Curl-Up","category":"rehab","equipment":["bodyweight"],"primary":["abs"],"secondary":[],"difficulty":1,"instructions":["Lie on your back, one knee bent, hands under your lower back to keep its natural arch.","Lift the head and shoulders just slightly off the floor — no crunching.","Hold ~8–10s, breathe, lower. Don’t flatten the back."],"dosage":"3 × 3 · 8–10s holds","rationale":"Builds abdominal endurance while keeping the spine neutral — a low-back staple."}'::jsonb, 72, true),
  ('rehab-side-plank', '{"id":"rehab-side-plank","name":"Side Plank","category":"rehab","equipment":["bodyweight"],"primary":["abs"],"secondary":["lowerback","glutes"],"difficulty":2,"instructions":["On your side, forearm under your shoulder, knees or feet stacked.","Lift the hips into a straight line; brace the trunk.","Hold, breathe, lower. Drop to the knees to regress."],"dosage":"3 × 10–20s / side","rationale":"Trains the obliques and quadratus lumborum to brace the spine from the side."}'::jsonb, 73, true),
  ('rehab-bird-dog', '{"id":"rehab-bird-dog","name":"Bird-Dog","category":"rehab","equipment":["bodyweight"],"primary":["lowerback"],"secondary":["glutes","abs"],"difficulty":1,"instructions":["On hands and knees, brace your core, back flat.","Extend the opposite arm and leg until level with the trunk — no rotating or sagging.","Return under control; alternate sides."],"dosage":"3 × 6–8 / side","rationale":"Teaches the trunk to stay still while the limbs move — exactly what an angry back needs."}'::jsonb, 74, true),
  ('rehab-dead-bug', '{"id":"rehab-dead-bug","name":"Dead Bug","category":"rehab","equipment":["bodyweight"],"primary":["abs"],"secondary":["lowerback"],"difficulty":1,"instructions":["Lie on your back, arms up, hips and knees at 90°, low back gently pressed down.","Lower the opposite arm and leg toward the floor.","Return without letting the back arch; alternate."],"dosage":"2–3 × 8 / side","rationale":"Anti-extension core control that keeps the low back pinned and pain-free."}'::jsonb, 75, true),
  ('rehab-clamshell', '{"id":"rehab-clamshell","name":"Clamshell","category":"rehab","equipment":["bodyweight","bands"],"primary":["glutes"],"secondary":[],"difficulty":1,"instructions":["Lie on your side, knees bent ~45°, feet together (band above the knees optional).","Keeping feet touching, lift the top knee by rotating the hip open.","Lower slowly; don’t let the pelvis roll back."],"dosage":"2–3 × 12–15 / side","rationale":"Wakes up the glute med that stabilises the hip and pelvis."}'::jsonb, 76, true),
  ('rehab-glute-bridge-iso', '{"id":"rehab-glute-bridge-iso","name":"Glute Bridge Hold","category":"rehab","equipment":["bodyweight"],"primary":["glutes"],"secondary":["hamstrings"],"difficulty":1,"instructions":["Lie on your back, knees bent, feet flat.","Drive through the heels and lift the hips to a straight line.","Squeeze the glutes and hold; lower slowly."],"dosage":"3 × 20–30s","rationale":"Builds pain-free hip-extension strength and glute activation without loaded hinging."}'::jsonb, 77, true),
  ('rehab-90-90-hip', '{"id":"rehab-90-90-hip","name":"90/90 Hip Switch","category":"rehab","equipment":["bodyweight"],"primary":["glutes"],"secondary":[],"difficulty":1,"instructions":["Sit with one leg bent in front and the other to the side, both at ~90°.","Rotate both knees to the floor on the other side, staying tall.","Move slowly through a comfortable range."],"dosage":"2 × 8 switches","rationale":"Restores internal/external hip rotation that loaded squats and hinges depend on."}'::jsonb, 78, true),
  ('rehab-hip-flexor-stretch', '{"id":"rehab-hip-flexor-stretch","name":"Half-Kneeling Hip Flexor Stretch","category":"rehab","equipment":["bodyweight"],"primary":["glutes"],"secondary":["quads"],"difficulty":1,"instructions":["Half-kneel, back knee down, front foot flat.","Tuck the tailbone and shift gently forward until you feel a stretch in the front of the back hip.","Stay tall; breathe; don’t arch the back."],"dosage":"2 × 30s / side","rationale":"Lengthens a tight hip flexor that can tug on the hip and low back."}'::jsonb, 79, true),
  ('rehab-quad-set', '{"id":"rehab-quad-set","name":"Quad Set","category":"rehab","equipment":["bodyweight"],"primary":["quads"],"secondary":[],"difficulty":1,"instructions":["Sit with the leg straight.","Tighten the thigh to press the back of the knee down, lifting the heel slightly.","Hold ~5s, relax. Keep it pain-free."],"dosage":"3 × 10 · 5s holds","rationale":"The gentlest re-entry: switches the quad back on around an irritable knee with no joint movement."}'::jsonb, 80, true),
  ('rehab-wall-sit', '{"id":"rehab-wall-sit","name":"Wall Sit","category":"rehab","equipment":["bodyweight"],"primary":["quads"],"secondary":["glutes"],"difficulty":1,"instructions":["Lean your back on a wall and slide down toward a comfortable, pain-free angle.","Hold with knees tracking over the toes.","Stand and rest. Reduce the angle if it pinches."],"dosage":"3 × 20–45s","rationale":"Isometric quad loading is well-evidenced for calming patellar-tendon pain while building strength."}'::jsonb, 81, true),
  ('rehab-spanish-squat', '{"id":"rehab-spanish-squat","name":"Spanish Squat","category":"rehab","equipment":["bands"],"primary":["quads"],"secondary":["glutes"],"difficulty":2,"instructions":["Loop a sturdy band around a post and behind your knees.","Sit back against the band into a squat, shins fairly vertical.","Hold (or do slow reps), keeping weight in the heels."],"dosage":"3 × 30–45s (or 3 × 10 · 5s)","rationale":"A band-anchored isometric that loads the quad/patellar tendon heavily with minimal knee shear."}'::jsonb, 82, true),
  ('rehab-terminal-knee-extension', '{"id":"rehab-terminal-knee-extension","name":"Terminal Knee Extension","category":"rehab","equipment":["bands"],"primary":["quads"],"secondary":[],"difficulty":1,"instructions":["Loop a band behind the knee, anchored in front of you.","Start with a slight knee bend; straighten the knee fully against the band.","Control the return; keep the foot flat."],"dosage":"2–3 × 15 / side","rationale":"Strengthens the quad through the last few degrees of extension that knees often lose."}'::jsonb, 83, true),
  ('rehab-step-down', '{"id":"rehab-step-down","name":"Slow Step-Down","category":"rehab","equipment":["bodyweight"],"primary":["quads"],"secondary":["glutes"],"difficulty":2,"instructions":["Stand on a low step on one leg.","Slowly lower the other heel toward the floor (3s), keeping the knee tracking over the toes.","Drive back up. Lower the step height to regress."],"unilateral":true,"dosage":"2–3 × 8 / side","rationale":"Rebuilds eccentric control and confidence for stairs, squatting and landing."}'::jsonb, 84, true),
  ('rehab-ankle-alphabet', '{"id":"rehab-ankle-alphabet","name":"Ankle Alphabet","category":"rehab","equipment":["bodyweight"],"primary":["calves"],"secondary":[],"difficulty":1,"instructions":["Seated, lift one foot off the floor.","Slowly “draw” the alphabet with your big toe, moving only the ankle.","Keep it smooth and within comfort."],"dosage":"2 × full alphabet","rationale":"Restores pain-free range in every direction after a sprain."}'::jsonb, 85, true),
  ('rehab-ankle-dorsiflexion', '{"id":"rehab-ankle-dorsiflexion","name":"Banded Ankle Dorsiflexion","category":"rehab","equipment":["bands"],"primary":["calves"],"secondary":[],"difficulty":1,"instructions":["Loop a band around the front of the ankle, anchored behind you.","In a half-kneel or standing, drive the knee forward over the toes, heel down.","Return slowly; keep the heel planted."],"dosage":"2–3 × 12 / side","rationale":"Restores the forward-knee range that squatting, lunging and walking need."}'::jsonb, 86, true),
  ('rehab-single-leg-balance', '{"id":"rehab-single-leg-balance","name":"Single-Leg Balance","category":"rehab","equipment":["bodyweight"],"primary":["calves"],"secondary":["glutes"],"difficulty":1,"instructions":["Stand on one leg near a wall for support.","Hold your balance; progress by closing your eyes or standing on a cushion.","Keep the foot quiet and the arch lifted."],"unilateral":true,"dosage":"3 × 30s / side","rationale":"Rebuilds the ankle’s reflexive stability (proprioception) to cut re-sprain risk."}'::jsonb, 87, true),
  ('rehab-eccentric-calf-raise', '{"id":"rehab-eccentric-calf-raise","name":"Eccentric Calf Raise","category":"rehab","equipment":["bodyweight"],"primary":["calves"],"secondary":[],"difficulty":2,"instructions":["Rise onto both toes at the edge of a step.","Shift to one foot and lower the heel slowly (3–4s) below the step.","Use both feet to rise again. Keep it pain-tolerable."],"dosage":"3 × 12 · slow lower","rationale":"Slow eccentrics reload the calf and Achilles after the early irritable phase settles."}'::jsonb, 88, true),
  ('rehab-hamstring-bridge-iso', '{"id":"rehab-hamstring-bridge-iso","name":"Hamstring Bridge Hold","category":"rehab","equipment":["bodyweight"],"primary":["hamstrings"],"secondary":["glutes"],"difficulty":1,"instructions":["Lie on your back, heels on the floor with the knees bent ~20–30°.","Dig the heels in and lift the hips, loading the hamstrings.","Hold; lower slowly. Bend the knees more if it grabs."],"dosage":"3 × 20–30s","rationale":"Pain-free isometric loading is the safe first step back for a strained hamstring."}'::jsonb, 89, true),
  ('rehab-single-leg-rdl-light', '{"id":"rehab-single-leg-rdl-light","name":"Single-Leg RDL (light)","category":"rehab","equipment":["bodyweight","dumbbell"],"primary":["hamstrings"],"secondary":["glutes"],"difficulty":2,"instructions":["Stand on one leg, soft knee, light or no weight.","Hinge at the hip, reaching the chest forward and the free leg back, flat back.","Feel a gentle stretch, then return. Keep it pain-free."],"unilateral":true,"dosage":"2–3 × 8 / side","rationale":"Reloads the hamstring at length with control before returning to heavy hinging."}'::jsonb, 90, true),
  ('rehab-nordic-eccentric', '{"id":"rehab-nordic-eccentric","name":"Nordic Hamstring Curl (assisted)","category":"rehab","equipment":["bodyweight"],"primary":["hamstrings"],"secondary":["glutes"],"difficulty":3,"instructions":["Kneel with the ankles anchored (or held by a partner).","Keeping the body straight from knees to head, lower forward slowly under control.","Catch with the hands and push back up. Only when earlier stages are pain-free."],"dosage":"2–3 × 5 · slow lower","rationale":"The gold-standard eccentric for hamstring strength and re-injury prevention — late-stage."}'::jsonb, 91, true),
  ('rehab-prone-hamstring-curl', '{"id":"rehab-prone-hamstring-curl","name":"Prone Hamstring Curl","category":"rehab","equipment":["bodyweight","bands"],"primary":["hamstrings"],"secondary":[],"difficulty":1,"instructions":["Lie face down (add a light band around the ankle if available).","Curl the heel toward the glute, then lower slowly.","Keep the hips down and the movement smooth."],"dosage":"2–3 × 12–15","rationale":"Light knee-flexion volume to rebuild hamstring capacity early on."}'::jsonb, 92, true),
  ('rehab-strain-isometric', '{"id":"rehab-strain-isometric","name":"Pain-Free Isometric Hold","category":"rehab","equipment":["bodyweight"],"primary":[],"secondary":[],"difficulty":1,"instructions":["Take the muscle to a comfortable, pain-free length.","Contract gently against light resistance (or your own hand) and hold — no movement.","Stay well inside the pain rule; breathe normally and relax between holds."],"dosage":"3–5 × 30–45s","rationale":"Gentle isometrics calm a freshly strained muscle and begin loading it without movement."}'::jsonb, 93, true),
  ('rehab-strain-eccentric', '{"id":"rehab-strain-eccentric","name":"Light Eccentric","category":"rehab","equipment":["bodyweight","dumbbell"],"primary":[],"secondary":[],"difficulty":1,"instructions":["Use a light load through a comfortable range.","Lower slowly (3–4s), emphasizing the lengthening phase.","Keep it pain-tolerable; add load only as it stays comfortable."],"dosage":"3 × 10 · slow lower","rationale":"Once the early irritability settles, slow eccentrics rebuild a strained muscle’s capacity."}'::jsonb, 94, true),
  ('rehab-strain-rom', '{"id":"rehab-strain-rom","name":"Progressive Range Rebuild","category":"rehab","equipment":["bodyweight"],"primary":[],"secondary":[],"difficulty":1,"instructions":["Move the muscle through its current pain-free range, unloaded.","Each session, nudge the range a little further as it allows.","Stop short of sharp pain; smooth and controlled throughout."],"dosage":"2–3 × 10","rationale":"Restores full, confident range before you return the muscle to heavier loading."}'::jsonb, 95, true)
